mapper.select:
SELECT DISTINCT TIPO_ORIGEN as "tipoOrigen", CONDICION as "condicion"
FROM ACE_LPA_CONFIG_PLANT
WHERE ID_PLANTILLALPA = #{id_plantilla}
  AND ID_ENTIDAD = #{id_entidad}

SELECT VALOR_ORIGEN
FROM ACE_LPA_CONFIG_PLANT
WHERE TIPO_ORIGEN IN ('ETIQUETA', 'LISTA')
  AND ID_ENTIDAD = #{id_entidad}
  AND ID_PLANTILLALPA = #{id_plantilla}

SELECT ID_ENTIDAD as entidad, ID_PLANTILLALPA as id, LPA_ETIQUETA as lpaEtiqueta,
TIPO_ORIGEN as tipoOrigen, VALOR_ORIGEN as valorOrigen, CONDICION as condicion
FROM ACE_LPA_CONFIG_PLANT
WHERE ID_PLANTILLALPA = #{id_plantilla} AND ID_ENTIDAD = #{id_entidad}

    AND TIPO_ORIGEN = #{tipo_origen}


    AND CONDICION = #{condicion}

ORDER BY LPA_ETIQUETA

mapper.delete:
DELETE
FROM ACE_LPA_CONFIG_PLANT
WHERE ID_PLANTILLALPA = #{id}
  AND ID_ENTIDAD = #{entidad}
  AND LPA_ETIQUETA = #{lpaEtiqueta}

DELETE
FROM ACE_LPA_CONFIG_PLANT
WHERE ID_PLANTILLALPA = #{idPlantilla}
  AND ID_ENTIDAD = #{entidad}

mapper.update:
UPDATE ACE_LPA_CONFIG_PLANT
SET TIPO_ORIGEN  = #{tipoOrigen},
    VALOR_ORIGEN = #{valorOrigen},
    CONDICION    = #{condicion}
WHERE ID_PLANTILLALPA = #{id}
  AND ID_ENTIDAD = #{entidad}
  AND LPA_ETIQUETA = #{lpaEtiqueta}

